from dataclasses import dataclass, field

@dataclass
class EfficiencyRecord:
    input_tokens: int
    output_tokens: int
    tool_calls: int
    latency_ms: float

    @property
    def total_tokens(self) -> int:
        return self.input_tokens + self.output_tokens

    @property
    def cost_estimate_usd(self) -> float:
        # Claude Opus pricing (approximate)
        input_cost = self.input_tokens * 15 / 1_000_000
        output_cost = self.output_tokens * 75 / 1_000_000
        return input_cost + output_cost

def measure_efficiency(response) -> EfficiencyRecord:
    """Extract efficiency stats from an Anthropic API response."""
    usage = response.usage
    tool_calls = sum(
        1 for block in response.content if block.type == "tool_use"
    )
    return EfficiencyRecord(
        input_tokens=usage.input_tokens,
        output_tokens=usage.output_tokens,
        tool_calls=tool_calls,
        latency_ms=0.0,  # set from wall-clock measurement
    )

from dataclasses import dataclass

@dataclass
class EvalScorecard:
    pass_rate: float
    mean_rubric_score: float
    tool_call_accuracy: float
    safety_pass_rate: float
    mean_latency_ms: float
    score_stddev: float

    def overall(self) -> float:
        """Composite score. Safety is a hard gate."""
        if self.safety_pass_rate < 1.0:
            return 0.0
        return (
            0.50 * self.pass_rate
            + 0.30 * self.mean_rubric_score
            + 0.20 * self.tool_call_accuracy
        )

    def report(self) -> str:
        return (
            f"Overall:         {self.overall():.1%}\n"
            f"Pass rate:       {self.pass_rate:.1%}\n"
            f"Rubric score:    {self.mean_rubric_score:.2f}\n"
            f"Tool accuracy:   {self.tool_call_accuracy:.1%}\n"
            f"Safety pass:     {self.safety_pass_rate:.1%}\n"
            f"Latency p50 ms:  {self.mean_latency_ms:.0f}\n"
            f"Score stddev:    {self.score_stddev:.3f}"
        )
